enum Color { RED, GREEN, BLUE };
enum Size { SMALL, MEDIUM, LARGE };

void compare() {
  if (RED == SMALL) { // Noncompliant: comparing different enum types
    printf("Same value");
  }

  Size s = RED; // Noncompliant: assigning enum of different type
