compliant:
enum Color { RED, GREEN, BLUE };
enum Size { SMALL, MEDIUM, LARGE };

void compare() {
  Color c1 = RED;
  Color c2 = BLUE;

  if (c1 == c2) { // Compliant: comparing same enum type
    printf("Same color");
  }

  Size s = MEDIUM; // Compliant: assigning correct enum type
}
